## 4. How Channel Plugins Declare Capabilities

### In the Plugin Code:
```typescript
const capabilities: ChannelCapabilities = {
  chatTypes: ["direct", "group"],  // Supports 1:1 and group messages
  polls: true,                      // Can send polls
  reactions: false,                 // Cannot react to messages
  edit: false,                       // Cannot edit messages
  unsend: false,                    // Cannot unsend messages
  reply: true,                       // Can reply to specific messages
  media: true,                       // Can send media (images, files, etc.)
  threads: true,                    // Can send in threads
  // ... etc
};
```

### Text Chunk Limit (for 4000 char limit):
```typescript
const outbound: ChannelOutboundAdapter = {
  deliveryMode: "direct",
  textChunkLimit: 4000,  // 4000 character limit per message
  chunker: (text, limit) => {
    // Custom chunking logic for 4000 char boundaries
    // Return array of chunks
  },
  chunkerMode: "text",  // "text" or "markdown"
  // ... send methods
};
```

### Direct vs Group Chat Handling:
```typescript
const messaging: ChannelMessagingAdapter = {
  inferTargetChatType: (params: { to: string }) => {
    // Return "direct", "group", or "channel" based on target format
    if (params.to.startsWith("user:")) return "direct";
    if (params.to.startsWith("group:")) return "group";
    return undefined;
  },
};
```

