## 6. Complete Channel Plugin Example Walkthrough

From `docs/plugins/sdk-channel-plugins.md`:

### Step 1: Package & Manifest
```json
{
  "name": "@myorg/openclaw-pulseboard",
  "version": "1.0.0",
  "type": "module",
  "openclaw": {
    "extensions": ["./index.ts"],
    "setupEntry": "./setup-entry.ts",
    "channel": {
      "id": "pulseboard",
      "label": "PulseBoard",
      "blurb": "Connect OpenClaw to PulseBoard"
    }
  }
}
```

### Step 2: Build Plugin Object
```typescript
import { createChatChannelPlugin, createChannelPluginBase } from "openclaw/plugin-sdk/core";

type ResolvedAccount = {
  accountId: string | null;
  token: string;
  allowFrom: string[];
  dmPolicy: string | undefined;
};

export const pulseboardPlugin = createChatChannelPlugin<ResolvedAccount>({
  base: createChannelPluginBase({
    id: "pulseboard",
    setup: {
      resolveAccount(cfg, accountId) {
        const section = (cfg.channels as Record<string, any>)?.["pulseboard"];
        return {
          accountId: accountId ?? null,
          token: section?.token,
          allowFrom: section?.allowFrom ?? [],
          dmPolicy: section?.dmSecurity,
        };
      },
    },
  }),

  security: {
    dm: {
      channelKey: "pulseboard",
      resolvePolicy: (account) => account.dmPolicy,
      resolveAllowFrom: (account) => account.allowFrom,
      defaultPolicy: "allowlist",
    },
  },

  pairing: {
    text: {
      idLabel: "PulseBoard username",
      message: "Send this code to verify:",
      notify: async ({ target, code }) => {
        await pulseboardApi.sendDm(target, `Code: ${code}`);
      },
    },
  },

  threading: { topLevelReplyToMode: "reply" },

  outbound: {
    attachedResults: {
      channel: "pulseboard",
      sendText: async (params) => {
        const result = await pulseboardApi.sendMessage(params.to, params.text);
        return { messageId: result.id };
      },
      sendMedia: async (params) => {
        await pulseboardApi.sendFile(params.to, params.mediaUrl);
      },
    },
    base: { deliveryMode: "direct" },
  },
});
```

### Step 3: Entry Point
```typescript
import { defineChannelPluginEntry } from "openclaw/plugin-sdk/core";
import { pulseboardPlugin } from "./src/channel.js";

export default defineChannelPluginEntry({
  id: "pulseboard",
  name: "PulseBoard",
  description: "PulseBoard channel plugin",
  plugin: pulseboardPlugin,
  registerCliMetadata(api) {
    api.registerCli(/* ... */);
  },
});
```

### Step 4: Setup Entry
```typescript
import { defineSetupPluginEntry } from "openclaw/plugin-sdk/core";
import { pulseboardPlugin } from "./src/channel.js";

export default defineSetupPluginEntry(pulseboardPlugin);
```

