### Step 8 — `extensions/pulseboard/src/client.ts`

A thin fictional HTTP client stub. No real dependencies — uses the built-in `fetch` API.

```typescript
// Fictional PulseBoard API client.
// Uses the standard fetch API; no external runtime dependencies.

export const DEFAULT_SERVER_URL = "https://api.pulseboard.example";

export type PulseBoardClientOptions = {
  apiToken: string;
  serverUrl?: string;
};

export type SendMessageResult = {
  messageId: string;
  boardName: string | null;
  to: string;
};

export class PulseBoardClient {
  private readonly apiToken: string;
  private readonly serverUrl: string;

  constructor(opts: PulseBoardClientOptions) {
    this.apiToken = opts.apiToken;
    this.serverUrl = (opts.serverUrl ?? DEFAULT_SERVER_URL).replace(/\/$/, "");
  }

  private headers(): HeadersInit {
    return {
      Authorization: `Bearer ${this.apiToken}`,
      "Content-Type": "application/json",
    };
  }

  /** Send a message to a board (group). Board name without leading #. */
  async postToBoard(boardName: string, text: string): Promise<SendMessageResult> {
    const res = await fetch(`${this.serverUrl}/boards/${encodeURIComponent(boardName)}/messages`, {
      method: "POST",
      headers: this.headers(),
      body: JSON.stringify({ text }),
    });
    if (!res.ok) {
      throw new Error(`PulseBoard board post failed: ${res.status} ${res.statusText}`);
    }
    const data = (await res.json()) as { id: string };
    return { messageId: data.id, boardName, to: `#${boardName}` };
  }

  /** Send a direct message to a user. */
  async sendDm(username: string, text: string): Promise<SendMessageResult> {
    const res = await fetch(`${this.serverUrl}/dms/${encodeURIComponent(username)}`, {
      method: "POST",
      headers: this.headers(),
      body: JSON.stringify({ text }),
    });
    if (!res.ok) {
      throw new Error(`PulseBoard DM failed: ${res.status} ${res.statusText}`);
    }
    const data = (await res.json()) as { id: string };
    return { messageId: data.id, boardName: null, to: username };
  }
}
```

