```typescript
export const pulseboardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (API Token)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin boards and direct messages via PulseBoard",
      quickstartAllowFrom: true,
    },
    capabilities: {
      chatTypes: ["direct", "group"],   // Both DM and board (group) messaging
      media: false,
      blockStreaming: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: PulseBoardChannelConfigSchema,
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      ...pulseBoardConfigAdapter,       // createScopedChannelConfigAdapter or createTopLevelChannelConfigAdapter
      isConfigured: (account) => account.configured,
      describeAccount: (account) => describeAccountSnapshot({ account, configured: account.configured, extra: { username: account.username, serverUrl: account.serverUrl } }),
    },
    messaging: {
      normalizeTarget: normalizePulseBoardTarget,
      targetResolver: {
        looksLikeId: (input) => {
          const t = input.trim();
          return t.startsWith("#") || /^@?[a-z0-9][a-z0-9-_.]{0,63}$/i.test(t);
        },
        hint: "<#board-name|@username>",
