import type { DmPolicy, MarkdownConfig, OpenClawConfig } from "../runtime-api.js";

/** Per-board group configuration (mirrors IrcChannelConfig pattern). */
export type PulseBoardGroupConfig = {
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  requireMention?: boolean;
  systemPrompt?: string;
};

/** Top-level + per-account config stored under channels.pulseboard.*. */
export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** PulseBoard API token. Also reads PULSEBOARD_API_TOKEN env var for the default account. */
  apiToken?: string;
  /** PulseBoard server base URL. Defaults to https://api.pulseboard.example. */
  serverUrl?: string;
  /** Bot username on PulseBoard. Also reads PULSEBOARD_USERNAME env var for the default account. */
  username?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  /** Named board configs keyed by board name (without the leading #). */
  boards?: Record<string, PulseBoardGroupConfig>;
  /** Override the default 4000-character chunk limit for this account. */
  textChunkLimit?: number;
  markdown?: MarkdownConfig;
};

/** Multi-account shape: base config + optional named accounts map. */
export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

/** Narrows OpenClawConfig to include the pulseboard channel section. */
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

/** Shape of a single inbound event received from the PulseBoard streaming API. */
export type PulseBoardInboundMessage = {
  messageId: string;
  /** null for direct messages; board name (without '#') for board posts. */
  boardName: string | null;
  senderUsername: string;
  text: string;
  /** Unix timestamp in milliseconds. */
  timestamp: number;
  isDirect: boolean;
};

