import { createAccountListHelpers } from "openclaw/plugin-sdk/account-helpers";
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import { resolveMergedAccountConfig } from "openclaw/plugin-sdk/account-resolution";
import type { CoreConfig, PulseBoardAccountConfig } from "./types.js";

export const DEFAULT_SERVER_URL = "https://api.pulseboard.example";

/** Fully resolved PulseBoard account with all fields non-optional. */
export type ResolvedPulseBoardAccount = {
  accountId: string;
  enabled: boolean;
  name?: string;
  /** true when both apiToken and username are present. */
  configured: boolean;
  apiToken: string;
  serverUrl: string;
  username: string;
  config: PulseBoardAccountConfig;
};

const {
  listAccountIds: listPulseBoardAccountIds,
  resolveDefaultAccountId: resolveDefaultPulseBoardAccountId,
} = createAccountListHelpers("pulseboard", { normalizeAccountId });
export { listPulseBoardAccountIds, resolveDefaultPulseBoardAccountId };

function mergeAccountConfig(cfg: CoreConfig, accountId: string): PulseBoardAccountConfig {
  return resolveMergedAccountConfig<PulseBoardAccountConfig>({
    channelConfig: cfg.channels?.pulseboard as PulseBoardAccountConfig | undefined,
    accounts: cfg.channels?.pulseboard?.accounts as
      | Record<string, Partial<PulseBoardAccountConfig>>
      | undefined,
    accountId,
    omitKeys: ["defaultAccount"],
    normalizeAccountId,
  });
}

function resolveApiToken(accountId: string, config: PulseBoardAccountConfig): string {
  // Env var applies only to the default account for security.
  if (accountId === DEFAULT_ACCOUNT_ID) {
    const envToken = process.env.PULSEBOARD_API_TOKEN?.trim();
    if (envToken) {
      return envToken;
    }
  }
  return config.apiToken?.trim() ?? "";
}

function resolveUsername(accountId: string, config: PulseBoardAccountConfig): string {
  if (accountId === DEFAULT_ACCOUNT_ID) {
    const envUser = process.env.PULSEBOARD_USERNAME?.trim();
    if (envUser) {
      return envUser;
    }
  }
  return config.username?.trim() ?? "";
}

function resolveServerUrl(accountId: string, config: PulseBoardAccountConfig): string {
  if (config.serverUrl?.trim()) {
    return config.serverUrl.trim();
  }
  if (accountId === DEFAULT_ACCOUNT_ID) {
    const envUrl = process.env.PULSEBOARD_SERVER_URL?.trim();
    if (envUrl) {
      return envUrl;
    }
  }
  return DEFAULT_SERVER_URL;
}

export function resolvePulseBoardAccount(params: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(params.accountId);
  const pbCfg = params.cfg.channels?.pulseboard;
  const baseEnabled = pbCfg?.enabled !== false;
  const merged = mergeAccountConfig(params.cfg, accountId);
  const accountEnabled = merged.enabled !== false;
  const enabled = baseEnabled && accountEnabled;

  const apiToken = resolveApiToken(accountId, merged);
  const username = resolveUsername(accountId, merged);
  const serverUrl = resolveServerUrl(accountId, merged);

  return {
    accountId,
    enabled,
    name: merged.name?.trim() || undefined,
    configured: Boolean(apiToken && username),
    apiToken,
    serverUrl,
    username,
    config: merged,
  };
}

export function listEnabledPulseBoardAccounts(cfg: CoreConfig): ResolvedPulseBoardAccount[] {
  return listPulseBoardAccountIds(cfg)
    .map((accountId) => resolvePulseBoardAccount({ cfg, accountId }))
    .filter((account) => account.enabled);
}

