// Fictional PulseBoard REST + long-poll API client.
// Uses the standard Fetch API — no external runtime dependencies required.

export const DEFAULT_SERVER_URL = "https://api.pulseboard.example";

export type PulseBoardClientOptions = {
  apiToken: string;
  serverUrl?: string;
};

export type SendMessageResult = {
  messageId: string;
  /** null for direct messages; board name (without '#') for board posts. */
  boardName: string | null;
  to: string;
};

/** An inbound event received from the PulseBoard streaming endpoint. */
export type PulseBoardEvent = {
  id: string;
  type: "dm" | "board_message";
  /** null for DMs; board name (without '#') for board messages. */
  boardName: string | null;
  senderUsername: string;
  text: string;
  /** Unix timestamp in seconds. */
  timestamp: number;
};

/** Lightweight client for the fictional PulseBoard REST API. */
export class PulseBoardClient {
  private readonly apiToken: string;
  private readonly serverUrl: string;

  constructor(opts: PulseBoardClientOptions) {
    this.apiToken = opts.apiToken;
    this.serverUrl = (opts.serverUrl ?? DEFAULT_SERVER_URL).replace(/\/$/, "");
  }

  private headers(): Record<string, string> {
    return {
      Authorization: `Bearer ${this.apiToken}`,
      "Content-Type": "application/json",
    };
  }

  /**
   * Post a message to a named board (group chat).
   * Board name must not include the leading '#'.
   */
  async postToBoard(boardName: string, text: string): Promise<SendMessageResult> {
    const res = await fetch(
      `${this.serverUrl}/boards/${encodeURIComponent(boardName)}/messages`,
      {
        method: "POST",
        headers: this.headers(),
        body: JSON.stringify({ text }),
      },
    );
    if (!res.ok) {
      throw new Error(`PulseBoard board post failed: ${res.status} ${res.statusText}`);
    }
    const data = (await res.json()) as { id: string };
    return { messageId: data.id, boardName, to: `#${boardName}` };
  }

  /** Send a direct message to a user by their username. */
  async sendDm(username: string, text: string): Promise<SendMessageResult> {
    const res = await fetch(`${this.serverUrl}/dms/${encodeURIComponent(username)}`, {
      method: "POST",
      headers: this.headers(),
      body: JSON.stringify({ text }),
    });
    if (!res.ok) {
      throw new Error(`PulseBoard DM failed: ${res.status} ${res.statusText}`);
    }
    const data = (await res.json()) as { id: string };
    return { messageId: data.id, boardName: null, to: username };
  }

  /**
   * Long-poll for new inbound events since the given cursor.
   * Returns events and the next cursor to use on the following call.
   */
  async pollMessages(params: {
    cursor?: string;
    timeoutMs?: number;
    signal?: AbortSignal;
  }): Promise<{ events: PulseBoardEvent[]; nextCursor: string }> {
    const url = new URL(`${this.serverUrl}/stream`);
    if (params.cursor) {
      url.searchParams.set("after", params.cursor);
    }
    if (params.timeoutMs) {
      url.searchParams.set("timeout", String(Math.floor(params.timeoutMs / 1000)));
    }
    const res = await fetch(url.toString(), {
      headers: this.headers(),
      signal: params.signal,
    });
    if (!res.ok) {
      throw new Error(`PulseBoard poll failed: ${res.status} ${res.statusText}`);
    }
    const data = (await res.json()) as { events: PulseBoardEvent[]; cursor: string };
    return { events: data.events ?? [], nextCursor: data.cursor ?? "" };
  }
}

