import { resolveMarkdownTableMode } from "openclaw/plugin-sdk/config-runtime";
import { convertMarkdownTables } from "openclaw/plugin-sdk/text-runtime";
import { resolvePulseBoardAccount } from "./accounts.js";
import { PulseBoardClient } from "./client.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
};

export type SendPulseBoardResult = {
  messageId: string;
  to: string;
};

/** Returns true when the target references a board (starts with '#'). */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/**
 * Normalize a raw messaging target.
 *
 * - Board: `#board-name` — keeps the '#' prefix, lowercases, strips invalid chars.
 * - Direct: bare username — strips a leading '@', lowercases.
 *
 * Returns undefined for blank or otherwise invalid input.
 */
export function normalizePulseBoardTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  if (trimmed.startsWith("#")) {
    const name = trimmed.slice(1).toLowerCase().replace(/[^a-z0-9-_]/g, "");
    return name ? `#${name}` : undefined;
  }
  const user = trimmed.replace(/^@/, "").toLowerCase().replace(/[^a-z0-9-_.]/g, "");
  return user || undefined;
}

export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" ` +
        `(need apiToken and username in channels.pulseboard).`,
    );
  }

  const target = normalizePulseBoardTarget(to);
  if (!target) {
    throw new Error(`Invalid PulseBoard target: "${to}"`);
  }

  const tableMode = resolveMarkdownTableMode({
    cfg,
    channel: "pulseboard",
    accountId: account.accountId,
  });
  const prepared = convertMarkdownTables(text.trim(), tableMode);
  if (!prepared.trim()) {
    throw new Error("PulseBoard message must be non-empty");
  }

  const client = new PulseBoardClient({
    apiToken: account.apiToken,
    serverUrl: account.serverUrl,
  });

  if (isBoardTarget(target)) {
    const result = await client.postToBoard(target.slice(1), prepared);
    return { messageId: result.messageId, to: target };
  }

  const result = await client.sendDm(target, prepared);
  return { messageId: result.messageId, to: target };
}

