import { afterEach, describe, expect, it } from "vitest";
import type { CoreConfig } from "./types.js";
import { pulseboardPlugin } from "./channel.js";
import { clearPulseBoardRuntime } from "./runtime.js";
import {
  listPulseBoardAccountIds,
  resolvePulseBoardAccount,
  resolveDefaultPulseBoardAccountId,
} from "./accounts.js";
import { normalizePulseBoardTarget, isBoardTarget } from "./send.js";

function createConfiguredPulseBoardCfg(overrides: Record<string, unknown> = {}): CoreConfig {
  return {
    channels: {
      pulseboard: {
        apiToken: "pb_test_abc123",
        username: "test-bot",
        ...overrides,
      },
    },
  } as CoreConfig;
}

afterEach(() => {
  clearPulseBoardRuntime();
});

// ---------------------------------------------------------------------------
// Plugin meta
// ---------------------------------------------------------------------------

describe("pulseboardPlugin meta", () => {
  it("has the correct id", () => {
    expect(pulseboardPlugin.id).toBe("pulseboard");
  });

  it("has the required meta fields", () => {
    expect(pulseboardPlugin.meta.label).toBe("PulseBoard");
    expect(pulseboardPlugin.meta.docsPath).toBe("/channels/pulseboard");
    expect(pulseboardPlugin.meta.blurb).toMatch(/bulletin board/i);
  });
});

// ---------------------------------------------------------------------------
// Capabilities
// ---------------------------------------------------------------------------

describe("pulseboardPlugin capabilities", () => {
  it("supports direct messages", () => {
    expect(pulseboardPlugin.capabilities.chatTypes).toContain("direct");
  });

  it("supports group / board messages", () => {
    expect(pulseboardPlugin.capabilities.chatTypes).toContain("group");
  });

  it("does not claim media support", () => {
    expect(pulseboardPlugin.capabilities.media).toBe(false);
  });
});

// ---------------------------------------------------------------------------
// Outbound adapter
// ---------------------------------------------------------------------------

describe("pulseboardPlugin outbound", () => {
  it("uses direct delivery mode", () => {
    expect(pulseboardPlugin.outbound?.deliveryMode).toBe("direct");
  });

  it("enforces the 4000-character chunk limit", () => {
    expect(pulseboardPlugin.outbound?.textChunkLimit).toBe(4000);
  });

  it("provides a chunker function", () => {
    expect(typeof pulseboardPlugin.outbound?.chunker).toBe("function");
  });

  it("chunks text correctly when a limit is applied", () => {
    const chunker = pulseboardPlugin.outbound?.chunker;
    if (!chunker) throw new Error("outbound.chunker missing");
    // Should split on word boundary
    expect(chunker("hello world", 5)).toEqual(["hello", "world"]);
  });
});

// ---------------------------------------------------------------------------
// Config adapter
// ---------------------------------------------------------------------------

describe("pulseboardPlugin config", () => {
  it("listAccountIds returns empty for unconfigured", () => {
    const cfg = { channels: {} } as CoreConfig;
    expect(pulseboardPlugin.config.listAccountIds(cfg)).toEqual([]);
  });

  it("listAccountIds returns default when token + username present", () => {
    const cfg = createConfiguredPulseBoardCfg();
    const ids = pulseboardPlugin.config.listAccountIds(cfg);
    expect(ids).toContain("default");
  });

  it("resolveAccount returns configured=true for a complete config", () => {
    const cfg = createConfiguredPulseBoardCfg();
    const account = pulseboardPlugin.config.resolveAccount(cfg, "default");
    expect(account.configured).toBe(true);
    expect(account.username).toBe("test-bot");
    expect(account.apiToken).toBe("pb_test_abc123");
  });

  it("resolveAccount returns configured=false when apiToken is missing", () => {
    const cfg = createConfiguredPulseBoardCfg({ apiToken: undefined });
    const account = pulseboardPlugin.config.resolveAccount(cfg, "default");
    expect(account.configured).toBe(false);
  });

  it("resolveAccount returns configured=false when username is missing", () => {
    const cfg = createConfiguredPulseBoardCfg({ username: undefined });
    const account = pulseboardPlugin.config.resolveAccount(cfg, "default");
    expect(account.configured).toBe(false);
  });
});

// ---------------------------------------------------------------------------
// Messaging adapter
// ---------------------------------------------------------------------------

describe("pulseboardPlugin messaging", () => {
  function requireLooksLikeId() {
    const fn = pulseboardPlugin.messaging?.targetResolver?.looksLikeId;
    if (!fn) throw new Error("messaging.targetResolver.looksLikeId missing");
    return fn;
  }

  function requireNormalizeTarget() {
    const fn = pulseboardPlugin.messaging?.normalizeTarget;
    if (!fn) throw new Error("messaging.normalizeTarget missing");
    return fn;
  }

  function requireInferChatType() {
    const fn = pulseboardPlugin.messaging?.inferTargetChatType;
    if (!fn) throw new Error("messaging.inferTargetChatType missing");
    return fn;
  }

  it("recognizes a board target", () => {
    expect(requireLooksLikeId()("#general")).toBe(true);
  });

  it("recognizes a plain username target", () => {
    expect(requireLooksLikeId()("alice")).toBe(true);
    expect(requireLooksLikeId()("@bob")).toBe(true);
  });

  it("rejects empty strings", () => {
    expect(requireLooksLikeId())("")).toBe(false);
  });

  it("normalizes a board target: strips invalid chars, keeps #", () => {
    expect(requireNormalizeTarget()("#General Ops")).toBe("#generalops");
    expect(requireNormalizeTarget()("#dev-team")).toBe("#dev-team");
  });

  it("normalizes a DM target: strips @, lowercases", () => {
    expect(requireNormalizeTarget())("@Alice")).toBe("alice");
    expect(requireNormalizeTarget())("Bob")).toBe("bob");
  });

  it("returns undefined for blank input", () => {
    expect(requireNormalizeTarget())("  ")).toBeUndefined();
  });

  it("infers group chat type for # targets", () => {
    expect(requireInferChatType()({ to: "#general" })).toBe("group");
  });

  it("infers direct chat type for username targets", () => {
    expect(requireInferChatType()({ to: "alice" })).toBe("direct");
  });
});

// ---------------------------------------------------------------------------
// Pairing adapter
// ---------------------------------------------------------------------------

describe("pulseboardPlugin pairing", () => {
  it("has the correct id label", () => {
    expect(pulseboardPlugin.pairing?.idLabel).toBe("pulseBoardUser");
  });

  it("normalizeAllowEntry strips @ and lowercases", () => {
    const normalize = pulseboardPlugin.pairing?.normalizeAllowEntry;
    if (!normalize) throw new Error("pairing.normalizeAllowEntry missing");
    expect(normalize("@Alice")).toBe("alice");
    expect(normalize("BOB")).toBe("bob");
    expect(normalize("  charlie  ")).toBe("charlie");
  });
});

// ---------------------------------------------------------------------------
// Security adapter
// ---------------------------------------------------------------------------

describe("pulseboardPlugin security", () => {
  it("resolveDmPolicy returns a policy for a configured account", () => {
    const resolveDmPolicy = pulseboardPlugin.security?.resolveDmPolicy;
    if (!resolveDmPolicy) throw new Error("security.resolveDmPolicy missing");

    const cfg = createConfiguredPulseBoardCfg({
      dmPolicy: "allowlist",
      allowFrom: ["alice", "@bob"],
    });
    const account = pulseboardPlugin.config.resolveAccount(cfg, "default");
    const result = resolveDmPolicy({ cfg, account, accountId: "default" });

    expect(result).toBeDefined();
    expect(result?.policy).toBe("allowlist");
    expect(result?.allowFrom).toEqual(["alice", "@bob"]);
  });

  it("normalizeEntry in dm policy strips @ prefix", () => {
    const resolveDmPolicy = pulseboardPlugin.security?.resolveDmPolicy;
    if (!resolveDmPolicy) throw new Error("security.resolveDmPolicy missing");

    const cfg = createConfiguredPulseBoardCfg({
      dmPolicy: "allowlist",
      allowFrom: ["@Alice"],
    });
    const account = pulseboardPlugin.config.resolveAccount(cfg, "default");
    const result = resolveDmPolicy({ cfg, account, accountId: "default" });

    expect(result?.normalizeEntry?.("@Alice")).toBe("alice");
  });
});

// ---------------------------------------------------------------------------
// Status adapter
// ---------------------------------------------------------------------------

describe("pulseboardPlugin status", () => {
  it("has a default runtime state", () => {
    expect(pulseboardPlugin.status?.defaultRuntime).toEqual(
      expect.objectContaining({
        accountId: "default",
        running: false,
      }),
    );
  });
});

// ---------------------------------------------------------------------------
// Account helpers
// ---------------------------------------------------------------------------

describe("listPulseBoardAccountIds", () => {
  it("returns empty when not configured", () => {
    expect(listPulseBoardAccountIds({ channels: {} } as CoreConfig)).toEqual([]);
  });

  it("returns default when token + username are set", () => {
    expect(listPulseBoardAccountIds(createConfiguredPulseBoardCfg())).toContain("default");
  });
});

describe("resolveDefaultPulseBoardAccountId", () => {
  it("returns default when configured", () => {
    expect(resolveDefaultPulseBoardAccountId(createConfiguredPulseBoardCfg())).toBe("default");
  });
});

describe("resolvePulseBoardAccount", () => {
  it("resolves a fully configured account", () => {
    const cfg = createConfiguredPulseBoardCfg({ name: "My Bot" });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.accountId).toBe("default");
    expect(account.configured).toBe(true);
    expect(account.name).toBe("My Bot");
    expect(account.apiToken).toBe("pb_test_abc123");
    expect(account.username).toBe("test-bot");
  });

  it("resolves an unconfigured account with defaults", () => {
    const account = resolvePulseBoardAccount({ cfg: { channels: {} } as CoreConfig });
    expect(account.configured).toBe(false);
    expect(account.apiToken).toBe("");
    expect(account.username).toBe("");
  });

  it("respects enabled=false", () => {
    const cfg = createConfiguredPulseBoardCfg({ enabled: false });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.enabled).toBe(false);
    expect(account.configured).toBe(true);
  });
});

// ---------------------------------------------------------------------------
// normalizePulseBoardTarget / isBoardTarget helpers
// ---------------------------------------------------------------------------

describe("normalizePulseBoardTarget", () => {
  it("normalizes board names", () => {
    expect(normalizePulseBoardTarget("#general")).toBe("#general");
    expect(normalizePulseBoardTarget("#Dev-Team_1")).toBe("#dev-team_1");
  });

  it("normalizes DM usernames", () => {
    expect(normalizePulseBoardTarget("alice")).toBe("alice");
    expect(normalizePulseBoardTarget("@Alice")).toBe("alice");
  });

  it("returns undefined for empty input", () => {
    expect(normalizePulseBoardTarget("")).toBeUndefined();
    expect(normalizePulseBoardTarget("   ")).toBeUndefined();
  });

  it("returns undefined for a board name with no valid chars after #", () => {
    expect(normalizePulseBoardTarget("#!!!")).toBeUndefined();
  });
});

describe("isBoardTarget", () => {
  it("returns true for # targets", () => {
    expect(isBoardTarget("#general")).toBe(true);
  });

  it("returns false for DM targets", () => {
    expect(isBoardTarget("alice")).toBe(false);
    expect(isBoardTarget("@alice")).toBe(false);
  });
});

