import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import { adaptScopedAccountAccessor, createScopedChannelConfigAdapter, createScopedDmSecurityResolver } from "openclaw/plugin-sdk/channel-config-helpers";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import { buildPassiveChannelStatusSummary } from "openclaw/plugin-sdk/extension-shared";
import { createComputedAccountStatusAdapter } from "openclaw/plugin-sdk/status-helpers";
import {
  buildBaseChannelStatusSummary,
  chunkTextForOutbound,
  createChannelPairingController,
  DEFAULT_ACCOUNT_ID,
  PAIRING_APPROVED_MESSAGE,
  createDefaultChannelRuntimeState,
  type ChannelPlugin,
} from "../runtime-api.js";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
  type ResolvedPulseBoardAccount,
} from "./accounts.js";
import { PulseBoardChannelConfigSchema } from "./config-schema.js";
import { dispatchPulseBoardInbound } from "./inbound.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { normalizePulseBoardTarget, sendMessagePulseBoard } from "./send.js";
import { pulseBoardSetupAdapter, pulseBoardSetupWizard } from "./setup-surface.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";
import { PulseBoardClient } from "./client.js";

const pulseBoardConfigAdapter = createScopedChannelConfigAdapter<
  ResolvedPulseBoardAccount,
  ResolvedPulseBoardAccount,
  CoreConfig
>({
  sectionKey: "pulseboard",
  listAccountIds: listPulseBoardAccountIds,
  resolveAccount: adaptScopedAccountAccessor(resolvePulseBoardAccount),
  defaultAccountId: resolveDefaultPulseBoardAccountId,
  // Fields cleared when a user runs "openclaw setup pulseboard --clear"
  clearBaseFields: ["name", "apiToken", "serverUrl", "username"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom
      .map((entry) => String(entry).replace(/^@/, "").trim().toLowerCase())
      .filter(Boolean),
});

const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
  normalizeEntry: (raw) => raw.replace(/^@/, "").trim().toLowerCase(),
});

export const pulseboardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (API Token)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin boards and direct messages via the PulseBoard API.",
      quickstartAllowFrom: true,
    },
    capabilities: {
      // Supports both 1:1 direct messages and named-board group posts.
      chatTypes: ["direct", "group"],
      media: false,
      blockStreaming: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: PulseBoardChannelConfigSchema,
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      ...pulseBoardConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: {
            username: account.username,
            serverUrl: account.serverUrl,
          },
        }),
    },
    messaging: {
      // Normalize targets: `#board-name` for boards, plain username for DMs.
      normalizeTarget: normalizePulseBoardTarget,
      targetResolver: {
        looksLikeId: (input) => {
          const t = input.trim();
          return t.startsWith("#") || /^@?[a-z0-9][a-z0-9-_.]{0,63}$/i.test(t);
        },
        hint: "<#board-name|@username>",
      },
      // Routing: '#' prefix → group, everything else → direct.
      inferTargetChatType: ({ to }) => (to.startsWith("#") ? "group" : "direct"),
    },
    status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
      defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
      buildChannelSummary: ({ account, snapshot }) => ({
        ...buildBaseChannelStatusSummary(snapshot),
        username: account.username,
        serverUrl: account.serverUrl,
      }),
      resolveAccountSnapshot: ({ account }) => ({
        accountId: account.accountId,
        name: account.name,
        enabled: account.enabled,
        configured: account.configured,
        extra: {
          username: account.username,
          serverUrl: account.serverUrl,
        },
      }),
    }),
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account as ResolvedPulseBoardAccount;

        if (!account.configured) {
          throw new Error(
            `PulseBoard is not configured for account "${account.accountId}" ` +
              `(need apiToken and username in channels.pulseboard).`,
          );
        }

        ctx.log?.info(
          `[${account.accountId}] starting PulseBoard provider (username: ${account.username})`,
        );

        const runtime = getPulseBoardRuntime();
        const pairing = createChannelPairingController({
          core: runtime,
          channel: "pulseboard",
          accountId: account.accountId,
        });

        const client = new PulseBoardClient({
          apiToken: account.apiToken,
          serverUrl: account.serverUrl,
        });

        let cursor = "";

        // Long-poll loop — runs until the abortSignal fires.
        while (!ctx.abortSignal.aborted) {
          try {
            const { events, nextCursor } = await client.pollMessages({
              cursor,
              timeoutMs: 30_000,
              signal: ctx.abortSignal,
            });
            cursor = nextCursor || cursor;

            for (const event of events) {
              if (ctx.abortSignal.aborted) {
                break;
              }
              const message: PulseBoardInboundMessage = {
                messageId: event.id,
                boardName: event.boardName,
                senderUsername: event.senderUsername,
                text: event.text,
                timestamp: event.timestamp * 1000,
                isDirect: event.type === "dm",
              };

              try {
                // Handle pairing handshakes before normal dispatch.
                const isPairingHandled = await pairing.tryHandlePairingReply({
                  senderId: event.senderUsername,
                  rawBody: event.text,
                });
                if (isPairingHandled) {
                  continue;
                }

                await dispatchPulseBoardInbound({
                  cfg: ctx.cfg as CoreConfig,
                  runtime,
                  accountId: account.accountId,
                  message,
                  log: ctx.log,
                });
              } catch (err) {
                ctx.log?.error?.(
                  `[${account.accountId}] error dispatching PulseBoard event ${event.id}: ${String(err)}`,
                );
              }
            }
          } catch (err) {
            if (ctx.abortSignal.aborted) {
              break;
            }
            ctx.log?.warn?.(
              `[${account.accountId}] PulseBoard poll error (retrying): ${String(err)}`,
            );
            // Brief backoff before retrying to avoid tight error loops.
            await new Promise<void>((resolve) => {
              const timer = setTimeout(resolve, 5_000);
              ctx.abortSignal.addEventListener("abort", () => {
                clearTimeout(timer);
                resolve();
              });
            });
          }
        }

        ctx.log?.info(`[${account.accountId}] PulseBoard provider stopped`);
      },
    },
  },

  pairing: {
    text: {
      idLabel: "pulseBoardUser",
      message: PAIRING_APPROVED_MESSAGE,
      // Strip leading '@' and lowercase before storing in allowFrom.
      normalizeAllowEntry: (entry) => entry.replace(/^@/, "").trim().toLowerCase(),
      notify: async ({ id, message }) => {
        await sendMessagePulseBoard(id, message);
      },
    },
  },

  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },

  outbound: {
    base: {
      deliveryMode: "direct",
      chunker: chunkTextForOutbound,
      chunkerMode: "markdown",
      // PulseBoard enforces a 4000-character limit per message.
      textChunkLimit: 4000,
    },
    attachedResults: {
      channel: "pulseboard",
      sendText: async ({ cfg, to, text, accountId }) =>
        await sendMessagePulseBoard(to, text, {
          cfg: cfg as CoreConfig,
          accountId: accountId ?? undefined,
        }),
      sendMedia: async ({ cfg, to, text, mediaUrl, accountId }) =>
        await sendMessagePulseBoard(to, mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text, {
          cfg: cfg as CoreConfig,
          accountId: accountId ?? undefined,
        }),
    },
  },
});

