import {
  DEFAULT_ACCOUNT_ID,
  dispatchInboundDirectDmWithRuntime,
  dispatchInboundReplyWithBase,
} from "../runtime-api.js";
import type { OpenClawConfig, PluginRuntime } from "../runtime-api.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

type Logger = {
  info?: (msg: string) => void;
  warn?: (msg: string) => void;
  error?: (msg: string) => void;
  debug?: (msg: string) => void;
};

/**
 * Dispatch a single inbound PulseBoard event to the OpenClaw runtime.
 *
 * - DMs are routed via dispatchInboundDirectDmWithRuntime (access-checked).
 * - Board (group) messages are routed via resolveAgentRoute + dispatchInboundReplyWithBase,
 *   which applies the standard session, envelope, and reply pipeline.
 */
export async function dispatchPulseBoardInbound(params: {
  cfg: CoreConfig;
  runtime: PluginRuntime;
  accountId: string;
  message: PulseBoardInboundMessage;
  log?: Logger;
}): Promise<void> {
  const { cfg, runtime, accountId, message, log } = params;
  const { messageId, senderUsername, text, timestamp, isDirect, boardName } = message;

  if (isDirect) {
    await dispatchInboundDirectDmWithRuntime({
      cfg: cfg as OpenClawConfig,
      runtime,
      channel: "pulseboard",
      channelLabel: "PulseBoard",
      accountId,
      peer: { kind: "direct", id: senderUsername },
      senderId: senderUsername,
      senderAddress: senderUsername,
      recipientAddress: accountId === DEFAULT_ACCOUNT_ID ? "pulseboard" : accountId,
      conversationLabel: senderUsername,
      rawBody: text,
      messageId,
      timestamp,
      deliver: async (payload) => {
        const outboundText =
          payload && typeof payload === "object" && "text" in payload
            ? String((payload as { text?: string }).text ?? "")
            : "";
        if (!outboundText.trim()) {
          return;
        }
        // Delivery for inline replies — convert markdown tables before logging.
        // The main outbound path goes through the outbound adapter in channel.ts.
        const tableMode = runtime.channel.text.resolveMarkdownTableMode({
          cfg: cfg as OpenClawConfig,
          channel: "pulseboard",
          accountId,
        });
        const converted = runtime.channel.text.convertMarkdownTables(outboundText, tableMode);
        log?.debug?.(`[${accountId}] PulseBoard DM reply to ${senderUsername}: ${converted}`);
      },
      onRecordError: (err) => {
        log?.error?.(
          `[${accountId}] failed recording PulseBoard inbound session: ${String(err)}`,
        );
      },
      onDispatchError: (err, info) => {
        log?.error?.(`[${accountId}] PulseBoard ${info.kind} reply failed: ${String(err)}`);
      },
    });
    return;
  }

  // Group / board message dispatch.
  // boardName is guaranteed non-null when isDirect is false.
  const board = boardName ?? "unknown";
  const peerId = `#${board}`;

  log?.debug?.(`[${accountId}] PulseBoard board message: board=${peerId} from=${senderUsername}`);

  // Resolve the agent route for this board peer.
  const route = runtime.channel.routing.resolveAgentRoute({
    cfg: cfg as OpenClawConfig,
    channel: "pulseboard",
    accountId,
    peer: { kind: "group", id: peerId },
  });

  const storePath = runtime.channel.session.resolveStorePath(
    (cfg as OpenClawConfig).session?.store,
    { agentId: route.agentId },
  );

  const envelopeOptions = runtime.channel.reply.resolveEnvelopeFormatOptions(
    cfg as OpenClawConfig,
  );
  const previousTimestamp = runtime.channel.session.readSessionUpdatedAt({
    storePath,
    sessionKey: route.sessionKey,
  });

  const body = runtime.channel.reply.formatAgentEnvelope({
    channel: "PulseBoard",
    from: senderUsername,
    timestamp,
    previousTimestamp,
    envelope: envelopeOptions,
    body: text,
  });

  const ctxPayload = runtime.channel.reply.finalizeInboundContext({
    Body: body,
    RawBody: text,
    CommandBody: text,
    From: `pulseboard:board:${peerId}`,
    To: `pulseboard:${peerId}`,
    SessionKey: route.sessionKey,
    AccountId: route.accountId,
    ChatType: "group",
    ConversationLabel: peerId,
    SenderName: senderUsername,
    SenderId: senderUsername,
    GroupSubject: peerId,
    Provider: "pulseboard",
    Surface: "pulseboard",
    MessageSid: messageId,
    Timestamp: timestamp,
    OriginatingChannel: "pulseboard",
    OriginatingTo: `pulseboard:${peerId}`,
  });

  await dispatchInboundReplyWithBase({
    cfg: cfg as OpenClawConfig,
    channel: "pulseboard",
    accountId: route.accountId,
    route,
    storePath,
    ctxPayload,
    core: runtime,
    deliver: async (payload) => {
      const outboundText =
        payload && typeof payload === "object" && "text" in payload
          ? String((payload as { text?: string }).text ?? "")
          : "";
      if (!outboundText.trim()) {
        return;
      }
      log?.debug?.(`[${accountId}] PulseBoard board reply to ${peerId}`);
    },
    onRecordError: (err) => {
      log?.error?.(`[${accountId}] failed recording PulseBoard group session: ${String(err)}`);
    },
    onDispatchError: (err, info) => {
      log?.error?.(`[${accountId}] PulseBoard group ${info.kind} reply failed: ${String(err)}`);
    },
  });
}

