        let cursor = "";

        // Long-poll loop — runs until the abortSignal fires.
        while (!ctx.abortSignal.aborted) {
          try {
            const { events, nextCursor } = await client.pollMessages({
              cursor,
              timeoutMs: 30_000,
              signal: ctx.abortSignal,
            });
            cursor = nextCursor || cursor;

            for (const event of events) {
              if (ctx.abortSignal.aborted) {
                break;
              }
              const message: PulseBoardInboundMessage = {
                messageId: event.id,
                boardName: event.boardName,
                senderUsername: event.senderUsername,
                text: event.text,
                timestamp: event.timestamp * 1000,
                isDirect: event.type === "dm",
              };

              try {
                await dispatchPulseBoardInbound({
                  cfg: ctx.cfg as CoreConfig,
                  runtime,
                  accountId: account.accountId,
                  message,
                  log: ctx.log,
                });
              } catch (err) {
                ctx.log?.error?.(
                  `[${account.accountId}] error dispatching PulseBoard event ${event.id}: ${String(err)}`,
                );
              }
            }
          } catch (err) {
            if (ctx.abortSignal.aborted) {
              break;
            }
            ctx.log?.warn?.(
              `[${account.accountId}] PulseBoard poll error (retrying): ${String(err)}`,
            );
            // Brief backoff before retrying to avoid tight error loops.
            await new Promise<void>((resolve) => {
              const timer = setTimeout(resolve, 5_000);
              ctx.abortSignal.addEventListener("abort", () => {
                clearTimeout(timer);
                resolve();
              });
            });
          }
        }

        ctx.log?.info(`[${account.accountId}] PulseBoard provider stopped`);
      },
    },
  },

  pairing: {
    text: {
      idLabel: "pulseBoardUser",
      message: PAIRING_APPROVED_MESSAGE,
      // Strip leading '@' and lowercase before storing in allowFrom.
      normalizeAllowEntry: (entry) => entry.replace(/^@/, "").trim().toLowerCase(),
      notify: async ({ id, message }) => {
        await sendMessagePulseBoard(id, message);
      },
    },
  },

  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },

  outbound: {
    base: {
      deliveryMode: "direct",
      chunker: chunkTextForOutbound,
      chunkerMode: "markdown",
      // PulseBoard enforces a 4000-character limit per message.
      textChunkLimit: 4000,
    },
    attachedResults: {
      channel: "pulseboard",
      sendText: async ({ cfg, to, text, accountId }) =>
        await sendMessagePulseBoard(to, text, {
          cfg: cfg as CoreConfig,
          accountId: accountId ?? undefined,
        }),
      sendMedia: async ({ cfg, to, text, mediaUrl, accountId }) =>
        await sendMessagePulseBoard(to, mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text, {
          cfg: cfg as CoreConfig,
          accountId: accountId ?? undefined,
        }),
    },
  },
});

import type { ChannelSetupAdapter } from "openclaw/plugin-sdk/channel-setup";
import type { OpenClawConfig } from "openclaw/plugin-sdk/config-runtime";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import {
  createStandardChannelSetupStatus,
  createTopLevelChannelDmPolicy,
  createTopLevelChannelParsedAllowFromPrompt,
  formatDocsLink,
  mergeAllowFromEntries,
  parseSetupEntriesWithParser,
  patchTopLevelChannelConfigSection,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy, ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import { resolvePulseBoardAccount } from "./accounts.js";

const channel = "pulseboard" as const;

const PULSEBOARD_SETUP_HELP_LINES = [
  "Generate an API token from your PulseBoard account settings.",
  "Set your bot username to the account name you registered on PulseBoard.",
  "Server URL is optional; leave blank to use the PulseBoard cloud service.",
  "Env vars supported for the default account: PULSEBOARD_API_TOKEN, PULSEBOARD_USERNAME.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

const PULSEBOARD_ALLOW_FROM_HELP_LINES = [
  "Allowlist PulseBoard DMs by username.",
  "Examples:",
  "- alice",
  "- @bob",
  "Multiple entries: comma-separated.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

function parsePulseBoardAllowFrom(raw: string): { entries: string[]; error?: string } {
  return parseSetupEntriesWithParser(raw, (entry) => {
    const cleaned = entry.replace(/^@/, "").trim().toLowerCase();
    if (!cleaned) {
      return { error: "Empty username entry" };
    }
    if (!/^[a-z0-9-_.]+$/.test(cleaned)) {
      return { error: `Invalid PulseBoard username: ${entry}` };
    }
    return { value: cleaned };
  });
}

const promptPulseBoardAllowFrom = createTopLevelChannelParsedAllowFromPrompt({
  channel,
  defaultAccountId: DEFAULT_ACCOUNT_ID,
  noteTitle: "PulseBoard allowlist",
  noteLines: PULSEBOARD_ALLOW_FROM_HELP_LINES,
  message: "PulseBoard allowFrom",
  placeholder: "alice, @bob",
  parseEntries: parsePulseBoardAllowFrom,
  mergeEntries: ({ existing, parsed }) => mergeAllowFromEntries(existing, parsed),
});

const pulseBoardDmPolicy: ChannelSetupDmPolicy = createTopLevelChannelDmPolicy({
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => {
    const pulseboard = (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
      | { dmPolicy?: string }
      | undefined;
    return pulseboard?.dmPolicy ?? "pairing";
  },
  promptAllowFrom: promptPulseBoardAllowFrom,
});

export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: () => DEFAULT_ACCOUNT_ID,
  applyAccountName: ({ cfg, name }) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: name?.trim() ? { name: name.trim() } : {},
    }),
  validateInput: ({ input }) => {
    const typedInput = input as {
      useEnv?: boolean;
      apiToken?: string;
      username?: string;
      serverUrl?: string;
    };
    if (!typedInput.useEnv) {
      if (!typedInput.apiToken?.trim()) {
        return "PulseBoard requires --api-token or --use-env.";
      }
    }
    if (!typedInput.username?.trim()) {
      return "PulseBoard requires --username.";
    }
    if (typedInput.serverUrl?.trim()) {
      try {
        new URL(typedInput.serverUrl.trim());
      } catch {
        return `Invalid server URL: ${typedInput.serverUrl}`;
      }
    }
    return null;
  },
  applyAccountConfig: ({ cfg, input }) => {
    const typedInput = input as {
      useEnv?: boolean;
      apiToken?: string;
      username?: string;
      serverUrl?: string;
    };
    return patchTopLevelChannelConfigSection({
      cfg,
      channel,
      enabled: true,
      clearFields: typedInput.useEnv ? ["apiToken"] : undefined,
      patch: {
        ...(typedInput.useEnv ? {} : { apiToken: typedInput.apiToken?.trim() }),
        username: typedInput.username?.trim(),
        ...(typedInput.serverUrl?.trim() ? { serverUrl: typedInput.serverUrl.trim() } : {}),
      },
    });
  },
};

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  resolveAccountIdForConfigure: () => DEFAULT_ACCOUNT_ID,
  resolveShouldPromptAccountIds: () => false,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API token and username",
    configuredHint: "configured",
    unconfiguredHint: "needs API token and username",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      resolvePulseBoardAccount({ cfg: cfg as Parameters<typeof resolvePulseBoardAccount>[0]["cfg"] })
        .configured,
    resolveExtraStatusLines: ({ cfg }) => {
      const account = resolvePulseBoardAccount({
        cfg: cfg as Parameters<typeof resolvePulseBoardAccount>[0]["cfg"],
      });
      return account.configured ? [`Username: ${account.username}`] : [];
    },
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: PULSEBOARD_SETUP_HELP_LINES,
  },
  envShortcut: {
    prompt: "PULSEBOARD_API_TOKEN detected. Use env var?",
    preferredEnvVar: "PULSEBOARD_API_TOKEN",
    isAvailable: ({ accountId }) =>
      accountId === DEFAULT_ACCOUNT_ID && Boolean(process.env.PULSEBOARD_API_TOKEN?.trim()),
    apply: async ({ cfg }) =>
      patchTopLevelChannelConfigSection({
        cfg,
        channel,
        enabled: true,
        clearFields: ["apiToken"],
        patch: {},
      }),
  },
  credentials: [
    {
      inputKey: "apiToken",
      providerHint: channel,
      credentialLabel: "API token",
      preferredEnvVar: "PULSEBOARD_API_TOKEN",
      helpTitle: "PulseBoard API token",
      helpLines: PULSEBOARD_SETUP_HELP_LINES,
      envPrompt: "PULSEBOARD_API_TOKEN detected. Use env var?",
      keepPrompt: "PulseBoard API token already configured. Keep it?",
      inputPrompt: "PulseBoard API token",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({
          cfg: cfg as Parameters<typeof resolvePulseBoardAccount>[0]["cfg"],
          accountId,
        });
        return {
          accountConfigured: account.configured,
          hasConfiguredValue: Boolean(account.config.apiToken?.trim()),
          resolvedValue: account.config.apiToken?.trim(),
          envValue: process.env.PULSEBOARD_API_TOKEN?.trim(),
        };
      },
      applyUseEnv: async ({ cfg }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: ["apiToken"],
          patch: {},
        }),
      applySet: async ({ cfg, resolvedValue }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { apiToken: resolvedValue },
        }),
    },
  ],
  textInputs: [
    {
      inputKey: "username",
      message: "PulseBoard bot username",
      placeholder: "my-bot",
      required: true,
      applyEmptyValue: false,
      helpTitle: "PulseBoard username",
      helpLines: [
        "The username of your PulseBoard bot account.",
        "Env var: PULSEBOARD_USERNAME (default account only).",
      ],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({
          cfg: cfg as Parameters<typeof resolvePulseBoardAccount>[0]["cfg"],
          accountId,
        });
        return account.username;
      },
      keepPrompt: (value) => `PulseBoard username set to "${value}". Keep it?`,
      validate: ({ value }) => {
        const cleaned = value.replace(/^@/, "").trim();
        if (!cleaned) {
          return "Username is required.";
        }
        if (!/^[a-z0-9-_.]+$/i.test(cleaned)) {
          return "Username may only contain letters, numbers, hyphens, underscores, and dots.";
        }
        return undefined;
      },
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { username: value.replace(/^@/, "").trim() },
        }),
    },
    {
      inputKey: "serverUrl",
      message: "PulseBoard server URL (optional, leave blank for cloud)",
      placeholder: "https://api.pulseboard.example",
      required: false,
      applyEmptyValue: true,
      helpTitle: "PulseBoard server URL",
      helpLines: [
        "Leave blank to use the default PulseBoard cloud API.",
        "Set this for self-hosted PulseBoard deployments.",
      ],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({
          cfg: cfg as Parameters<typeof resolvePulseBoardAccount>[0]["cfg"],
          accountId,
        });
        return account.config.serverUrl ?? "";
      },
      keepPrompt: (value) => `Server URL set to "${value}". Keep it?`,
      validate: ({ value }) => {
        if (!value.trim()) {
          return undefined;
        }
        try {
          new URL(value.trim());
          return undefined;
        } catch {
          return `Invalid URL: ${value}`;
        }
      },
      applySet: async ({ cfg, value }) => {
        const trimmed = value.trim();
        return patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: trimmed ? undefined : ["serverUrl"],
          patch: trimmed ? { serverUrl: trimmed } : {},
        });
      },
    },
  ],
  dmPolicy: pulseBoardDmPolicy,
  disable: (cfg: OpenClawConfig) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: { enabled: false },
    }),
};

